from pathlib import Path
import shutil

FILES = {'src/services/scan_history_service.py': '"""Speichert und lädt Diagnoseläufe für Verlauf und Vergleich."""\n\nfrom __future__ import annotations\n\nimport json\nfrom collections import Counter\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Any\n\nSTATUSES = ("OK", "INFO", "HINWEIS", "WARNUNG", "KRITISCH", "FEHLER")\n\n\nclass ScanHistoryService:\n    def __init__(self, directory: str | Path = "data/scans") -> None:\n        self.directory = Path(directory)\n\n    def save(self, results: list[tuple[str, dict]]) -> Path:\n        self.directory.mkdir(parents=True, exist_ok=True)\n        now = datetime.now()\n        counts = Counter(self._rating(result) for _, result in results)\n\n        payload = {\n            "schema_version": 2,\n            "created_at": now.isoformat(timespec="seconds"),\n            "status_counts": {\n                status: counts.get(status, 0)\n                for status in STATUSES\n            },\n            "results": [\n                {\n                    "title": title,\n                    "status": self._rating(result),\n                    "details": self._json_safe(result),\n                }\n                for title, result in results\n            ],\n        }\n\n        path = self.directory / now.strftime("scan_%Y-%m-%d_%H-%M-%S.json")\n        path.write_text(\n            json.dumps(payload, ensure_ascii=False, indent=2),\n            encoding="utf-8",\n        )\n        return path\n\n    def load_recent(self, limit: int = 10) -> list[dict]:\n        return list(reversed(self.list_scans(limit=limit)))\n\n    def list_scans(self, limit: int | None = None) -> list[dict]:\n        if not self.directory.exists():\n            return []\n\n        paths = sorted(self.directory.glob("scan_*.json"), reverse=True)\n        if limit is not None:\n            paths = paths[:limit]\n\n        scans = []\n        for path in paths:\n            try:\n                scan = json.loads(path.read_text(encoding="utf-8"))\n            except (OSError, json.JSONDecodeError):\n                continue\n\n            scan["_path"] = str(path.resolve())\n            scan["_filename"] = path.name\n            scan["_has_details"] = bool(scan.get("results"))\n            scans.append(scan)\n\n        return scans\n\n    @staticmethod\n    def _rating(result: dict) -> str:\n        value = result.get("Bewertung", result.get("Status", "INFO"))\n        status = str(value).upper()\n        return status if status in STATUSES else "INFO"\n\n    @classmethod\n    def _json_safe(cls, value: Any) -> Any:\n        if isinstance(value, dict):\n            return {str(key): cls._json_safe(item) for key, item in value.items()}\n        if isinstance(value, (list, tuple, set)):\n            return [cls._json_safe(item) for item in value]\n        if isinstance(value, (str, int, float, bool)) or value is None:\n            return value\n        return str(value)\n', 'src/services/scan_comparison_service.py': '"""Vergleicht zwei gespeicherte Diagnoseläufe."""\n\nfrom __future__ import annotations\n\nfrom dataclasses import dataclass\n\nSTATUS_RANK = {\n    "OK": 0,\n    "INFO": 1,\n    "HINWEIS": 2,\n    "WARNUNG": 3,\n    "KRITISCH": 4,\n    "FEHLER": 5,\n}\n\n\n@dataclass(frozen=True)\nclass ComparisonItem:\n    title: str\n    old_status: str\n    new_status: str\n    change: str\n\n\nclass ScanComparisonService:\n    def compare(self, old_scan: dict, new_scan: dict) -> dict:\n        old_results = self._index(old_scan)\n        new_results = self._index(new_scan)\n        titles = sorted(set(old_results) | set(new_results))\n        summary = {\n            "VERBESSERT": 0,\n            "UNVERÄNDERT": 0,\n            "VERSCHLECHTERT": 0,\n            "NEU": 0,\n            "ENTFERNT": 0,\n        }\n        items = []\n\n        for title in titles:\n            old_item = old_results.get(title)\n            new_item = new_results.get(title)\n\n            if old_item is None:\n                old_status = "NICHT VORHANDEN"\n                new_status = new_item["status"]\n                change = "NEU"\n            elif new_item is None:\n                old_status = old_item["status"]\n                new_status = "NICHT VORHANDEN"\n                change = "ENTFERNT"\n            else:\n                old_status = old_item["status"]\n                new_status = new_item["status"]\n                change = self._classify(old_status, new_status)\n\n            summary[change] += 1\n            items.append(\n                ComparisonItem(\n                    title=title,\n                    old_status=old_status,\n                    new_status=new_status,\n                    change=change,\n                )\n            )\n\n        return {\n            "old_created_at": old_scan.get("created_at", "Unbekannt"),\n            "new_created_at": new_scan.get("created_at", "Unbekannt"),\n            "old_status_counts": old_scan.get("status_counts", {}),\n            "new_status_counts": new_scan.get("status_counts", {}),\n            "summary": summary,\n            "items": items,\n        }\n\n    @staticmethod\n    def _index(scan: dict) -> dict[str, dict]:\n        return {\n            str(item.get("title", "Unbenannte Prüfung")): {\n                "status": str(item.get("status", "INFO")).upper()\n            }\n            for item in scan.get("results", [])\n        }\n\n    @staticmethod\n    def _classify(old_status: str, new_status: str) -> str:\n        old_rank = STATUS_RANK.get(old_status, 1)\n        new_rank = STATUS_RANK.get(new_status, 1)\n        if new_rank < old_rank:\n            return "VERBESSERT"\n        if new_rank > old_rank:\n            return "VERSCHLECHTERT"\n        return "UNVERÄNDERT"\n', 'src/gui/comparison_window.py': '"""Fenster zum Vergleich zweier Diagnoseläufe."""\n\nfrom __future__ import annotations\n\nfrom datetime import datetime\nfrom pathlib import Path\nfrom tkinter import filedialog, messagebox\n\nimport customtkinter as ctk\nfrom matplotlib.backends.backend_tkagg import FigureCanvasTkAgg\nfrom matplotlib.figure import Figure\n\nfrom src.services.scan_comparison_service import ScanComparisonService\nfrom src.services.scan_history_service import STATUSES, ScanHistoryService\n\nCHANGE_STYLES = {\n    "VERBESSERT": ("Verbessert", ("#15803D", "#22C55E")),\n    "UNVERÄNDERT": ("Unverändert", ("#475569", "#94A3B8")),\n    "VERSCHLECHTERT": ("Verschlechtert", ("#B91C1C", "#EF4444")),\n    "NEU": ("Neu", ("#0369A1", "#38BDF8")),\n    "ENTFERNT": ("Entfernt", ("#7E22CE", "#A855F7")),\n}\n\n\nclass ComparisonWindow(ctk.CTkToplevel):\n    def __init__(self, master, history_service: ScanHistoryService) -> None:\n        super().__init__(master)\n        self.history_service = history_service\n        self.service = ScanComparisonService()\n        self.scan_by_label = {}\n        self.current = None\n\n        self.title("Diagnoseläufe vergleichen")\n        self.geometry("1100x800")\n        self.minsize(900, 650)\n        self.transient(master)\n        self.grid_columnconfigure(0, weight=1)\n        self.grid_rowconfigure(1, weight=1)\n\n        self._create_header()\n        self._create_body()\n        self._load_options()\n\n    def _create_header(self) -> None:\n        frame = ctk.CTkFrame(self, corner_radius=0)\n        frame.grid(row=0, column=0, sticky="ew")\n        ctk.CTkLabel(\n            frame,\n            text="Diagnosevergleich",\n            font=ctk.CTkFont(size=25, weight="bold"),\n        ).grid(row=0, column=0, padx=28, pady=(20, 3), sticky="w")\n        ctk.CTkLabel(\n            frame,\n            text="Vergleicht zwei gespeicherte Diagnoseläufe.",\n            text_color=("gray40", "gray70"),\n        ).grid(row=1, column=0, padx=28, pady=(0, 18), sticky="w")\n\n    def _create_body(self) -> None:\n        body = ctk.CTkScrollableFrame(self, fg_color="transparent")\n        body.grid(row=1, column=0, padx=14, pady=14, sticky="nsew")\n        body.grid_columnconfigure(0, weight=1)\n\n        selection = ctk.CTkFrame(body, corner_radius=12)\n        selection.grid(row=0, column=0, padx=8, pady=(4, 12), sticky="ew")\n        selection.grid_columnconfigure((0, 1), weight=1)\n\n        ctk.CTkLabel(selection, text="Älterer Scan").grid(\n            row=0, column=0, padx=16, pady=(14, 5), sticky="w"\n        )\n        ctk.CTkLabel(selection, text="Neuerer Scan").grid(\n            row=0, column=1, padx=16, pady=(14, 5), sticky="w"\n        )\n\n        self.old_menu = ctk.CTkOptionMenu(selection, values=["Keine Scans"])\n        self.old_menu.grid(row=1, column=0, padx=16, pady=(0, 14), sticky="ew")\n        self.new_menu = ctk.CTkOptionMenu(selection, values=["Keine Scans"])\n        self.new_menu.grid(row=1, column=1, padx=16, pady=(0, 14), sticky="ew")\n\n        actions = ctk.CTkFrame(selection, fg_color="transparent")\n        actions.grid(row=2, column=0, columnspan=2, pady=(0, 16))\n        self.compare_button = ctk.CTkButton(\n            actions, text="Scans vergleichen", command=self._compare\n        )\n        self.compare_button.grid(row=0, column=0, padx=6)\n        self.export_button = ctk.CTkButton(\n            actions,\n            text="Vergleich exportieren",\n            state="disabled",\n            command=self._export,\n        )\n        self.export_button.grid(row=0, column=1, padx=6)\n\n        self.summary = ctk.CTkFrame(body, fg_color="transparent")\n        self.summary.grid(row=1, column=0, padx=8, pady=(0, 12), sticky="ew")\n        self.summary_labels = {}\n        for column, change in enumerate(CHANGE_STYLES):\n            self.summary.grid_columnconfigure(column, weight=1, uniform="sum")\n            label, color = CHANGE_STYLES[change]\n            card = ctk.CTkFrame(self.summary, corner_radius=10, border_width=1)\n            card.grid(row=0, column=column, padx=4, sticky="ew")\n            ctk.CTkFrame(card, height=5, fg_color=color).grid(\n                row=0, column=0, padx=7, pady=(7, 3), sticky="ew"\n            )\n            value = ctk.CTkLabel(\n                card, text="0", font=ctk.CTkFont(size=22, weight="bold")\n            )\n            value.grid(row=1, column=0)\n            ctk.CTkLabel(card, text=label).grid(row=2, column=0, pady=(0, 9))\n            card.grid_columnconfigure(0, weight=1)\n            self.summary_labels[change] = value\n        self.summary.grid_remove()\n\n        self.chart_frame = ctk.CTkFrame(body, corner_radius=12)\n        self.chart_frame.grid(row=2, column=0, padx=8, pady=(0, 12), sticky="ew")\n        self.chart_frame.grid_columnconfigure(0, weight=1)\n        ctk.CTkLabel(\n            self.chart_frame,\n            text="Statusvergleich",\n            font=ctk.CTkFont(size=17, weight="bold"),\n        ).grid(row=0, column=0, padx=18, pady=(14, 3), sticky="w")\n\n        self.figure = Figure(figsize=(8.5, 2.8), dpi=100)\n        self.axes = self.figure.add_subplot(111)\n        self.canvas = FigureCanvasTkAgg(self.figure, master=self.chart_frame)\n        widget = self.canvas.get_tk_widget()\n        widget.configure(height=280)\n        widget.grid(row=1, column=0, padx=12, pady=(0, 12), sticky="ew")\n        self.chart_frame.grid_remove()\n\n        self.results_section = ctk.CTkFrame(body, corner_radius=12)\n        self.results_section.grid(\n            row=3, column=0, padx=8, pady=(0, 16), sticky="ew"\n        )\n        self.results_section.grid_columnconfigure(0, weight=1)\n        ctk.CTkLabel(\n            self.results_section,\n            text="Änderungen nach Diagnosebereich",\n            font=ctk.CTkFont(size=17, weight="bold"),\n        ).grid(row=0, column=0, padx=18, pady=(14, 8), sticky="w")\n        self.results = ctk.CTkFrame(self.results_section, fg_color="transparent")\n        self.results.grid(row=1, column=0, padx=10, pady=(0, 12), sticky="ew")\n        self.results.grid_columnconfigure(0, weight=1)\n        self.results_section.grid_remove()\n\n    def _load_options(self) -> None:\n        scans = [\n            scan\n            for scan in self.history_service.list_scans()\n            if scan.get("_has_details")\n        ]\n        if len(scans) < 2:\n            self.compare_button.configure(state="disabled")\n            messagebox.showinfo(\n                "Zwei neue Scans erforderlich",\n                "Führe nach dem Upgrade zwei neue Diagnosen aus.",\n                parent=self,\n            )\n            return\n\n        labels = []\n        for scan in scans:\n            label = self._label(scan)\n            labels.append(label)\n            self.scan_by_label[label] = scan\n\n        self.old_menu.configure(values=labels)\n        self.new_menu.configure(values=labels)\n        self.old_menu.set(labels[-1])\n        self.new_menu.set(labels[0])\n\n    def _compare(self) -> None:\n        old_scan = self.scan_by_label.get(self.old_menu.get())\n        new_scan = self.scan_by_label.get(self.new_menu.get())\n        if not old_scan or not new_scan:\n            return\n        if old_scan["_path"] == new_scan["_path"]:\n            messagebox.showwarning(\n                "Gleicher Scan",\n                "Wähle zwei unterschiedliche Scans.",\n                parent=self,\n            )\n            return\n        if old_scan.get("created_at", "") > new_scan.get("created_at", ""):\n            old_scan, new_scan = new_scan, old_scan\n\n        self.current = self.service.compare(old_scan, new_scan)\n        self._render_summary()\n        self._render_chart()\n        self._render_items()\n        self.summary.grid()\n        self.chart_frame.grid()\n        self.results_section.grid()\n        self.export_button.configure(state="normal")\n\n    def _render_summary(self) -> None:\n        for change, label in self.summary_labels.items():\n            label.configure(text=str(self.current["summary"].get(change, 0)))\n\n    def _render_chart(self) -> None:\n        self.axes.clear()\n        dark = ctk.get_appearance_mode() == "Dark"\n        bg = "#2B2B2B" if dark else "#F7F7F7"\n        fg = "#F3F4F6" if dark else "#1F2937"\n        self.figure.patch.set_facecolor(bg)\n        self.axes.set_facecolor(bg)\n\n        positions = list(range(len(STATUSES)))\n        width = 0.36\n        old_values = [\n            int(self.current["old_status_counts"].get(status, 0))\n            for status in STATUSES\n        ]\n        new_values = [\n            int(self.current["new_status_counts"].get(status, 0))\n            for status in STATUSES\n        ]\n        self.axes.bar(\n            [p - width / 2 for p in positions],\n            old_values,\n            width,\n            label="Älterer Scan",\n            color="#64748B",\n        )\n        self.axes.bar(\n            [p + width / 2 for p in positions],\n            new_values,\n            width,\n            label="Neuerer Scan",\n            color="#3B82F6",\n        )\n        self.axes.set_xticks(\n            positions,\n            ["OK", "Info", "Hinweis", "Warnung", "Kritisch", "Fehler"],\n        )\n        self.axes.set_ylabel("Anzahl")\n        self.axes.grid(axis="y", alpha=0.16)\n        self.axes.tick_params(colors=fg)\n        self.axes.yaxis.label.set_color(fg)\n        for spine in self.axes.spines.values():\n            spine.set_visible(False)\n        self.axes.legend(frameon=False, labelcolor=fg)\n        self.figure.tight_layout(pad=1.1)\n        self.canvas.draw_idle()\n\n    def _render_items(self) -> None:\n        for widget in self.results.winfo_children():\n            widget.destroy()\n\n        order = {\n            "VERSCHLECHTERT": 0,\n            "VERBESSERT": 1,\n            "NEU": 2,\n            "ENTFERNT": 3,\n            "UNVERÄNDERT": 4,\n        }\n        items = sorted(\n            self.current["items"],\n            key=lambda item: (order.get(item.change, 9), item.title),\n        )\n\n        for row, item in enumerate(items):\n            label, color = CHANGE_STYLES[item.change]\n            card = ctk.CTkFrame(self.results, corner_radius=9, border_width=1)\n            card.grid(row=row, column=0, padx=6, pady=5, sticky="ew")\n            card.grid_columnconfigure(0, weight=1)\n            ctk.CTkLabel(\n                card,\n                text=item.title,\n                anchor="w",\n                font=ctk.CTkFont(size=14, weight="bold"),\n            ).grid(row=0, column=0, padx=12, pady=(10, 2), sticky="w")\n            ctk.CTkLabel(\n                card,\n                text=f"{item.old_status}  →  {item.new_status}",\n                anchor="w",\n                text_color=("gray40", "gray70"),\n            ).grid(row=1, column=0, padx=12, pady=(0, 10), sticky="w")\n            ctk.CTkLabel(\n                card,\n                text=label,\n                width=140,\n                fg_color=color,\n                corner_radius=7,\n                font=ctk.CTkFont(size=11, weight="bold"),\n            ).grid(row=0, column=1, rowspan=2, padx=12, pady=12)\n\n    def _export(self) -> None:\n        path = filedialog.asksaveasfilename(\n            parent=self,\n            title="Diagnosevergleich speichern",\n            defaultextension=".md",\n            filetypes=[("Markdown", "*.md"), ("Text", "*.txt")],\n            initialfile="Diagnosevergleich.md",\n        )\n        if not path:\n            return\n\n        lines = [\n            "# Vergleich zweier Diagnoseläufe",\n            "",\n            f"Älterer Scan: {self.current[\'old_created_at\']}",\n            f"Neuerer Scan: {self.current[\'new_created_at\']}",\n            "",\n            "## Zusammenfassung",\n            "",\n        ]\n        for change, count in self.current["summary"].items():\n            lines.append(f"- {CHANGE_STYLES[change][0]}: {count}")\n\n        lines += [\n            "",\n            "## Änderungen",\n            "",\n            "| Diagnosebereich | Vorher | Nachher | Änderung |",\n            "|---|---|---|---|",\n        ]\n        for item in self.current["items"]:\n            lines.append(\n                f"| {item.title} | {item.old_status} | "\n                f"{item.new_status} | {CHANGE_STYLES[item.change][0]} |"\n            )\n\n        Path(path).write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n        messagebox.showinfo(\n            "Gespeichert",\n            f"Vergleich gespeichert:\\n\\n{path}",\n            parent=self,\n        )\n\n    @staticmethod\n    def _label(scan: dict) -> str:\n        value = str(scan.get("created_at", ""))\n        try:\n            formatted = datetime.fromisoformat(value).strftime("%d.%m.%Y %H:%M:%S")\n        except ValueError:\n            formatted = value or scan.get("_filename", "Scan")\n        return f"{formatted} | {scan.get(\'_filename\', \'\')}"\n'}

root = Path.cwd()
app_path = root / "src/gui/app.py"
backup_dir = root / "backup_before_comparison_upgrade"

if not app_path.exists():
    raise SystemExit("Das Skript muss im Projektordner ausgeführt werden.")

backup_dir.mkdir(parents=True, exist_ok=True)

for rel in ("src/gui/app.py", "src/services/scan_history_service.py", "build_exe.ps1"):
    source = root / rel
    if source.exists():
        target = backup_dir / rel
        target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(source, target)

for rel, text in FILES.items():
    path = root / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")
    print(f"Erstellt: {rel}")

content = app_path.read_text(encoding="utf-8")

import_anchor = "from src.gui.components.dashboard_extra_charts import DiskUsageChart, HistoryChart\n"
comparison_import = "from src.gui.comparison_window import ComparisonWindow\n"

if comparison_import not in content:
    if import_anchor not in content:
        raise RuntimeError("Importposition nicht gefunden.")
    content = content.replace(import_anchor, import_anchor + comparison_import, 1)

button_anchor = "        self.save_report_button.grid(\n            row=0,\n            column=1,\n            padx=6,\n        )\n"
button_block = button_anchor + "\n        self.compare_scans_button = ctk.CTkButton(\n            self.report_actions_frame,\n            text=\"Diagnosen vergleichen\",\n            width=190,\n            height=38,\n            command=self._open_comparison,\n        )\n        self.compare_scans_button.grid(\n            row=0,\n            column=2,\n            padx=6,\n        )\n"

if "self.compare_scans_button = ctk.CTkButton(" not in content:
    if button_anchor not in content:
        raise RuntimeError("Buttonposition nicht gefunden.")
    content = content.replace(button_anchor, button_block, 1)

method_anchor = "    def _open_report(self) -> None:\n"
method = "    def _open_comparison(self) -> None:\n        \"\"\"Öffnet den Vergleich gespeicherter Diagnoseläufe.\"\"\"\n\n        ComparisonWindow(\n            self,\n            history_service=self.history_service,\n        )\n\n"

if method not in content:
    if method_anchor not in content:
        raise RuntimeError("Methodenposition nicht gefunden.")
    content = content.replace(method_anchor, method + method_anchor, 1)

app_path.write_text(content, encoding="utf-8")
print("Aktualisiert: src/gui/app.py")

build_path = root / "build_exe.ps1"
if build_path.exists():
    build = build_path.read_text(encoding="utf-8")
    anchor = '    --paths "." `'
    for module in ("src.gui.comparison_window", "src.services.scan_comparison_service"):
        line = f'    --hidden-import "{module}" `'
        if line not in build and anchor in build:
            build = build.replace(anchor, anchor + "\n" + line, 1)
    build_path.write_text(build, encoding="utf-8")
    print("Aktualisiert: build_exe.ps1")

print()
print("Diagnosevergleich erfolgreich eingebaut.")
print("Führe danach zwei neue Diagnosen aus.")
print("Dann auf 'Diagnosen vergleichen' klicken.")
